{
  "terms": [
    {
      "term": "TT System",
      "simpleDefinition": "An earthing arrangement where the installation's earth connection is made through a local rod driven into the ground.",
      "anchor": "A local earth rod in the soil.",
      "misconception": "Believing that a TT system uses the supplier's cable sheath for its earth return path."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth conductors are kept separate throughout the entire supply and installation.",
      "anchor": "Separate earth and neutral conductors all the way from the source.",
      "misconception": "Confusing it with TN-C-S, where the conductors are combined in the supply cable."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth are combined in the supply cable but separated within the consumer's installation.",
      "anchor": "Combined supply conductors, but separate earth and neutral in the house.",
      "misconception": "Thinking that the earth and neutral remain combined inside the final circuits of the building."
    },
    {
      "term": "Circuit Protective Conductor (CPC)",
      "simpleDefinition": "The specific conductor that connects the metal parts of an individual circuit to the main earthing terminal.",
      "anchor": "The 'earth wire' found inside a standard circuit cable.",
      "misconception": "Using the term 'Earthing Conductor' when referring to a CPC."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's Main Earthing Terminal to the means of earthing (like an earth rod or supplier's terminal).",
      "anchor": "The single main cable connecting the whole house to the earth source.",
      "misconception": "Confusing this main link with the smaller CPCs used in individual circuits."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metal service pipes (like gas or water) to the main earthing terminal to keep them at the same potential.",
      "anchor": "The thick green-and-yellow cables connected to gas and water mains.",
      "misconception": "Thinking these conductors are meant to carry circuit fault currents like a CPC does."
    },
    {
      "term": "Supplementary Bonding",
      "simpleDefinition": "Additional earth connections used in high-risk areas, such as bathrooms, to connect metal parts together.",
      "anchor": "Extra earth links between metal pipes and equipment in a bathroom.",
      "misconception": "Assuming that supplementary bonding is required in every room of a dry installation."
    },
    {
      "term": "Protective Devices",
      "simpleDefinition": "Components such as fuses or circuit breakers (MCBs) that automatically cut off the power during a fault.",
      "anchor": "Fuses and MCBs that trip to stop the flow of electricity.",
      "misconception": "Believing these devices only protect against 'too many appliances' rather than being a critical part of the ADS safety system."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod, plate, or mesh buried in the ground to provide a physical connection to the Earth.",
      "anchor": "A copper-clad rod driven into the earth outside a building.",
      "misconception": "Thinking an earth electrode is required for TN-S or TN-C-S systems where the supplier provides the earth."
    }
  ],
  "anchorPhrases": [
    "TT uses a local rod",
    "TN-S means Separate",
    "TN-C-S means Combined supply",
    "CPC is for the circuit",
    "Earthing Conductor is the main link",
    "Bonding is for pipes",
    "ADS stands for Automatic Disconnection of Supply"
  ],
  "misconceptionTargets": [
    "Do not use 'earth wire' as a generic term; specify if it is a CPC, Earthing Conductor, or Bonding Conductor.",
    "The supplier does not always provide the earth connection (TT systems).",
    "Protective devices are part of the earthing safety chain, not just for overload protection."
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "Earthing systems are defined by how the installation connects back to the source of supply. In a TT system, the installation does not use the supplier's cable for its earth path. Instead, it relies on a local earth electrode, such as a copper-clad rod driven directly into the soil. This is common in rural areas or remote outbuildings.",
        "When the supplier provides the earth connection, we use TN systems. In a TN-S system, the 'S' stands for 'Separate.' This means the neutral and earth conductors are kept as two distinct wires throughout the entire network, from the transformer all the way into the property. The earth is often provided via the lead sheath of the supply cable.",
        "The most common modern arrangement is the TN-C-S system. Here, the 'C-S' stands for 'Combined-Separate.' The supplier combines the earth and neutral into a single conductor in the street cables, but these are separated into two distinct terminals once they enter the consumer's property. You must use these acronyms precisely, as they dictate how fault current returns to the source."
      ],
      "hint": "Focus on whether the earth and neutral are separate (S) or combined (C) in the supply, and remember that TT always requires a local rod."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that make up an ADS system.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety strategy that uses several specific components to clear faults. At the individual circuit level, we use a Circuit Protective Conductor (CPC). This is the specific conductor, such as the bare wire in a twin and earth cable, that connects the metal parts of a circuit to the consumer unit. Do not confuse this with the Earthing Conductor, which is the single main cable connecting the entire installation's main earthing terminal to the earth source or electrode.",
        "To prevent metal pipes from becoming live during a fault, we use main protective bonding. These are the thick green-and-yellow cables you see connected to the main gas and water services. In high-risk areas like bathrooms, supplementary bonding may be used to provide extra local connections between metal parts.",
        "The 'disconnection' in ADS is performed by protective devices, such as fuses or circuit breakers (MCBs), which trip to stop the flow of electricity during a fault. Finally, in TT systems, an earth electrode is the physical component buried in the ground to provide the earth connection. Using the correct terminology for each part is essential for professional communication and safety."
      ],
      "hint": "Distinguish between the CPC used in a single circuit and the Earthing Conductor that serves the whole building."
    }
  ]
}

